extends SceneTree

func _init() -> void:
	# Load the scene
	var scene: PackedScene = load("res://scenes/Animator.tscn")
	var instance: Node = scene.instantiate()
	root.add_child(instance)

	var controller: Node = instance.get_node("TweenController")

	# Track signals
	var sig_a := 0
	var sig_b := 0
	var sig_c := 0
	var sig_done := 0
	controller.step_a_complete.connect(func(): sig_a += 1)
	controller.step_b_complete.connect(func(): sig_b += 1)
	controller.step_c_complete.connect(func(): sig_c += 1)
	controller.animation_complete.connect(func(): sig_done += 1)

	var target: Node2D = instance.get_node("Target")

	# Verify initial state
	assert(target.position == Vector2.ZERO, "Initial position should be (0,0)")
	assert(target.rotation == 0.0, "Initial rotation should be 0")
	assert(target.scale == Vector2.ONE, "Initial scale should be (1,1)")
	assert(target.modulate == Color.WHITE, "Initial modulate should be white")
	print("PASS: Initial state correct")

	# Play the sequence
	var tween: Tween = controller.play_sequence()
	assert(tween != null, "play_sequence should return a Tween")
	assert(tween.is_valid(), "Tween should be valid")
	assert(controller.is_running(), "Should be running after play_sequence")

	# Pause and drive with custom_step
	tween.pause()

	# Helper to step and print state
	func step_and_check(t: float, expected: Dictionary) -> void:
		tween.custom_step(0.01)
		if expected.has("position"):
			var pos := target.position
			var exp: Vector2 = expected["position"]
			var ok := is_equal_approx(pos.x, exp.x) and is_equal_approx(pos.y, exp.y)
			if not ok:
				print("  FAIL at t=%.2f: position=(%.4f, %.4f), expected=(%.4f, %.4f)" % [t, pos.x, pos.y, exp.x, exp.y])
			else:
				print("  OK t=%.2f: position=(%.4f, %.4f)" % [t, pos.x, pos.y])
		if expected.has("scale"):
			var scl := target.scale
			var exp: Vector2 = expected["scale"]
			var ok := is_equal_approx(scl.x, exp.x) and is_equal_approx(scl.y, exp.y)
			if not ok:
				print("  FAIL at t=%.2f: scale=(%.4f, %.4f), expected=(%.4f, %.4f)" % [t, scl.x, scl.y, exp.x, exp.y])
			else:
				print("  OK t=%.2f: scale=(%.4f, %.4f)" % [t, scl.x, scl.y])
		if expected.has("modulate_a"):
			var exp_a: float = expected["modulate_a"]
			var ok := is_equal_approx(target.modulate.a, exp_a)
			if not ok:
				print("  FAIL at t=%.2f: modulate.a=%.4f, expected=%.4f" % [t, target.modulate.a, exp_a])
			else:
				print("  OK t=%.2f: modulate.a=%.4f" % [t, target.modulate.a])
		if expected.has("modulate"):
			var exp: Color = expected["modulate"]
			var cur := target.modulate
			var ok := is_equal_approx(cur.r, exp.r) and is_equal_approx(cur.g, exp.g) and is_equal_approx(cur.b, exp.b) and is_equal_approx(cur.a, exp.a)
			if not ok:
				print("  FAIL at t=%.2f: modulate=(%.4f,%.4f,%.4f,%.4f), expected=(%.4f,%.4f,%.4f,%.4f)" % [t, cur.r, cur.g, cur.b, cur.a, exp.r, exp.g, exp.b, exp.a])
			else:
				print("  OK t=%.2f: modulate=(%.4f,%.4f,%.4f,%.4f)" % [t, cur.r, cur.g, cur.b, cur.a])
		if expected.has("rotation"):
			var exp_rot: float = expected["rotation"]
			var ok := is_equal_approx(target.rotation, exp_rot)
			if not ok:
				print("  FAIL at t=%.2f: rotation=%.6f, expected=%.6f" % [t, target.rotation, exp_rot])
			else:
				print("  OK t=%.2f: rotation=%.6f" % [t, target.rotation])
		if expected.has("signals"):
			var exp_sigs: Dictionary = expected["signals"]
			var ok := sig_a == exp_sigs.get("a", sig_a) and sig_b == exp_sigs.get("b", sig_b) and sig_c == exp_sigs.get("c", sig_c) and sig_done == exp_sigs.get("done", sig_done)
			if not ok:
				print("  FAIL at t=%.2f: signals a=%d b=%d c=%d done=%d, expected a=%d b=%d c=%d done=%d" % [t, sig_a, sig_b, sig_c, sig_done, exp_sigs.get("a", 0), exp_sigs.get("b", 0), exp_sigs.get("c", 0), exp_sigs.get("done", 0)])
			else:
				print("  OK t=%.2f: signals a=%d b=%d c=%d done=%d" % [t, sig_a, sig_b, sig_c, sig_done])

	print("\n=== Checkpoint t=0.50 ===")
	# Need to step 50 times (0.01 * 50 = 0.50)
	for i in range(50):
		tween.custom_step(0.01)
	step_and_check(0.50, {"position": Vector2(100, 50), "signals": {"a": 0, "b": 0, "c": 0, "done": 0}})

	print("\n=== Checkpoint t=1.00 ===")
	for i in range(50):
		tween.custom_step(0.01)
	step_and_check(1.00, {"position": Vector2(200, 100), "signals": {"a": 1, "b": 0, "c": 0, "done": 0}})

	print("\n=== Checkpoint t=1.50 ===")
	for i in range(50):
		tween.custom_step(0.01)
	step_and_check(1.50, {"scale": Vector2(1.5, 1.5), "modulate_a": 0.75, "signals": {"a": 1, "b": 0, "c": 0, "done": 0}})

	print("\n=== Checkpoint t=2.00 ===")
	for i in range(50):
		tween.custom_step(0.01)
	step_and_check(2.00, {"scale": Vector2(2, 2), "modulate_a": 0.5, "signals": {"a": 1, "b": 1, "c": 0, "done": 0}})

	print("\n=== Checkpoint t=3.00 ===")
	for i in range(100):
		tween.custom_step(0.01)
	step_and_check(3.00, {"rotation": PI / 2.0, "signals": {"a": 1, "b": 1, "c": 1, "done": 0}})

	print("\n=== Checkpoint t=3.50 ===")
	for i in range(50):
		tween.custom_step(0.01)
	step_and_check(3.50, {"modulate": Color(0.5, 1.0, 1.0, 1.0), "signals": {"a": 1, "b": 1, "c": 1, "done": 1}})

	print("\n=== Final checks ===")
	print("is_running() = ", controller.is_running(), " (expected false)")
	assert(not controller.is_running(), "Should not be running after animation_complete")
	assert(sig_a == 1, "step_a_complete should fire exactly once, got %d" % sig_a)
	assert(sig_b == 1, "step_b_complete should fire exactly once, got %d" % sig_b)
	assert(sig_c == 1, "step_c_complete should fire exactly once, got %d" % sig_c)
	assert(sig_done == 1, "animation_complete should fire exactly once, got %d" % sig_done)
	print("ALL CHECKS PASSED")

	quit(0)

